Greedy insertion with regret heuristic considering both temporal feasibility and spatial proximity, falling back to empty/new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx     int
		delta   float64
		feasible bool
	}
	for jj := range oris {
		bestCand := cand{-1, 1e100, false}
		secondBest := cand{-1, 1e100, false}
		ori, des := oris[jj], dess[jj]
		shipID := total_ship + jj
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			if prevCost < 0 {
				continue
			}
			ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					delta := newCost - prevCost
					c := cand{ii, delta, true}
					if delta < bestCand.delta {
						secondBest = bestCand
						bestCand = c
					} else if delta < secondBest.delta {
						secondBest = c
					}
				}
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		regret := secondBest.delta - bestCand.delta
		selectedIdx := -1
		if bestCand.feasible {
			if regret <= 0 || dispatch.AssignsLen == 0 {
				selectedIdx = bestCand.idx
			} else {
				for ii := 0; ii < dispatch.AssignsLen; ii++ {
					prevCost := dispatch.Assigns[ii].Cost
					if prevCost < 0 {
						continue
					}
					ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
					if ok {
						dispatch.Assigns[ii].GenRoute()
						newCost := dispatch.Assigns[ii].Cost
						if newCost >= 0 {
							delta := newCost - prevCost
							combo := delta*0.7 + (delta-bestCand.delta)*0.3
							if combo < bestCand.delta*1.05 {
								selectedIdx = ii
							}
						}
						dispatch.Assigns[ii].RemoveShip(shipID)
						dispatch.Assigns[ii].GenRoute()
					}
					if selectedIdx >= 0 {
						break
					}
				}
				if selectedIdx < 0 {
					selectedIdx = bestCand.idx
				}
			}
		}
		if selectedIdx < 0 {
			seedIdx := dispatch.AssignsLen
			if seedIdx < MAXASSIGNS {
				ok := dispatch.Assigns[seedIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[seedIdx].GenRoute()
					if dispatch.Assigns[seedIdx].Cost >= 0 {
						dispatch.AssignsLen++
						selectedIdx = seedIdx
					} else {
						dispatch.Assigns[seedIdx].RemoveShip(shipID)
						dispatch.Assigns[seedIdx].GenRoute()
					}
				}
			}
		}
		if selectedIdx >= 0 {
			dispatch.Assigns[selectedIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[selectedIdx].GenRoute()
		} else {
			for ii := 0; ii < MAXASSIGNS; ii++ {
				ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						if ii >= dispatch.AssignsLen {
							dispatch.AssignsLen = ii + 1
						}
						break
					} else {
						dispatch.Assigns[ii].RemoveShip(shipID)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

